// src/utils/vietnameseFont.ts
// Font NotoSans (subset: Latin A-Z/a-z + toàn bộ ký tự tiếng Việt có
// dấu + số + 1 số dấu câu cơ bản) dạng base64, dùng để nhúng vào jsPDF.
//
// jsPDF chỉ có 14 font chuẩn (helvetica/times/courier) hỗ trợ
// WinAnsi/Latin-1 -> KHÔNG có glyph cho ký tự tiếng Việt có dấu
// (á, đ, ơ, ư...). Phải nhúng font TTF hỗ trợ Unicode qua VFS
// (doc.addFileToVFS + doc.addFont), nếu không in tiếng Việt sẽ ra
// ký tự rác kiểu "&H&Ó&A&...".
//
// Nguồn: NotoSans variable font (google/fonts repo, ofl/notosans),
// đã "instance" cố định weight 400 (Regular) / 700 (Bold), sau đó
// subset bằng pyftsubset để chỉ giữ glyph thực tế cần dùng (giảm từ
// ~650KB -> ~20KB mỗi file, tránh làm phình bundle FE).
// Nếu sau này cần thêm ký tự (icon, ký tự đặc biệt khác) mà bị thiếu
// glyph, phải subset lại font gốc với danh sách ký tự mới.

export const NOTOSANS_REGULAR_BASE64 = "";

export const NOTOSANS_BOLD_BASE64 = "";